<!doctype html><html lang="de"><head><meta charset="utf-8"><title>{{ $tour->number }}</title><style>body{font:14px Arial,sans-serif;color:#111;margin:30px}h1{margin-bottom:4px}.metrics{display:flex;gap:20px;margin:20px 0}.stop{page-break-inside:avoid;border-top:1px solid #bbb;padding:16px 0}.photos{display:flex;gap:8px;flex-wrap:wrap}.photos img{width:120px;height:90px;object-fit:cover}table{width:100%;border-collapse:collapse}td,th{border:1px solid #ccc;padding:6px;text-align:left}@media print{button{display:none}}</style></head><body><button onclick="print()">Drucken / als PDF speichern</button><h1>{{ $tour->title }}</h1><div>{{ $tour->number }} · {{ optional($tour->tour_date)->format('d.m.Y') }}</div><div class="metrics"><b>{{ $tour->planned_km }} Plan-km</b><b>{{ $tour->planned_drive_minutes }} Fahrminuten</b><b>{{ number_format($tour->margin,2,',','.') }} € Marge</b></div>@foreach($tour->stops as $stop)<section class="stop"><h2>{{ $loop->iteration }}. {{ $stop->title }}</h2><p>{{ $stop->address_snapshot['formatted'] ?? '' }} @if($stop->customer)· {{ $stop->customer->name }}@endif</p><p>{!! nl2br(e($stop->notes)) !!}</p>@if($stop->items->isNotEmpty())<table><thead><tr><th>Artikel</th><th>Menge</th><th>EK</th><th>Verkauf netto</th></tr></thead><tbody>@foreach($stop->items as $item)<tr><td>{{ $item->item_name }}</td><td>{{ $item->quantity }}</td><td>{{ $item->ek_snapshot }} €</td><td>{{ $item->actual_net_price }} €</td></tr>@endforeach</tbody></table>@endif @foreach($stop->comments as $comment)<p><b>{{ $comment->user?->name }}:</b> {{ $comment->body }}</p>@endforeach @if(request('photos'))<div class="photos">@foreach($stop->photos as $photo)<img src="{{ route('sck.media.show',$photo) }}">@endforeach</div>@endif</section>@endforeach</body></html>
